const { createClient } = require\('@supabase/supabase-js'\);
const sb = createClient\(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY\);

async function check\(\) {
  const { data: series } = await sb.from\('series'\).select\('*, bets\(*\)'\).eq\('user_id', '517bc9c6-a360-4182-ae31-0b2f3de9ec0f'\);

  // Group by subject + bet_type
  const groups = {};
  for \(const s of series\) {
    const key = s.subject + ' | ' + s.bet_type;
    if \(!groups[key]\) groups[key] = { series: [], totalStake: 0, totalWon: 0 };
    groups[key].series.push\(s\);
    for \(const b of s.bets\) {
      groups[key].totalStake += b.stake;
      if \(b.result === 'gagne'\) groups[key].totalWon += b.stake * b.odds;
    }
  }

  console.log\('Équipe | Gain net | Total Mise | Nb séries | Nb paris'\);
  console.log\('---'\);
  let totalNet = 0;
  const sorted = Object.entries\(groups\).sort\(\(a,b\) => a[0].localeCompare\(b[0]\)\);
  for \(const [key, g] of sorted\) {
    const net = \(g.totalWon - g.totalStake\).toFixed\(2\);
    const nbParis = g.series.reduce\(\(s, ser\) => s + ser.bets.length, 0\);
    totalNet += parseFloat\(net\);
    console.log\(key + ' | ' + net + '€ | ' + g.totalStake.toFixed\(2\) + '€ | ' + g.series.length + ' séries | ' + nbParis + ' paris'\);
  }
  console.log\('---'\);
  console.log\('TOTAL NET: ' + totalNet.toFixed\(2\) + '€'\);
}
